// Отримуємо перший елемент з попередньої ноди
const items = $input.all();

if (items.length === 0) {
  return [{ json: { error: "Немає даних від AI агента" } }];
}

// Витягуємо текст з поля output (це те, що згенерував AI)
const rawOutput = items[0].json.output;

if (!rawOutput) {
  return [{ json: { error: "Поле 'output' порожнє або не знайдено" } }];
}

try {
  // Очищаємо від можливих markdown-символів (якщо AI раптом додав ```json)
  const cleanString = rawOutput.replace(/```json/g, '').replace(/```/g, '').trim();

  // Парсимо в масив
  const parsedData = JSON.parse(cleanString);

  // Перетворюємо в окремі items для n8n
  const result = parsedData.map(item => ({
    json: {
      title: item.title || "Без назви",
      company: item.company || "Не вказано",
      link: item.link || "",
      description: item.description || "",
      source: item.source || "Unknown",
      ai_score: item.ai_score ? parseFloat(item.ai_score) : 0,
      ai_reason: item.ai_reason || "Аналіз відсутній"
    }
  }));

  return result;

} catch (e) {
  return [{ json: { error: "Помилка парсингу: " + e.message + ". Вхідні дані: " + rawOutput.substring(0, 100) } }];
}

const items = $input.all();

if (items.length === 0) {
  return [];
}

const data = items[0].json;
const results = [];

// Проходимо по масиву заголовків (їх 4, як і вакансій)
for (let i = 0; i < data.title.length; i++) {
  results.push({
    json: {
      title: data.title[i],
      // В описі беремо кожен другий елемент (0, 2, 4, 6), бо між ними сміття
      description: data.description[i * 2] 
        ? data.description[i * 2].replace(/\n/g, ' ').trim() 
        : '',
      link: 'https://www.work.ua' + data.link[i],
      pubDate: data.pubDate[i]
    }
  });
}

return results;

// Ми беремо шлях, який ти бачив у себе в Output, і перетворюємо його на список
const items = $input.first().json.rss.channel.item;

// Якщо вакансія лише одна, DOU присилає її як об'єкт. 
// Якщо багато — як масив. Робимо, щоб завжди був масив для n8n:
return Array.isArray(items) ? items.map(i => ({ json: i })) : [{ json: items }];

const items = $input.all();
const LIMIT = 10; // скільки вакансій максимум показати

// 1. Сортуємо за оцінкою (від високого до низького)
items.sort((a, b) => b.json.ai_score - a.json.ai_score);

// 2. Застосовуємо ліміт
const topJobs = items.slice(0, LIMIT);

// 3. Формуємо HTML повідомлення
let message = `
<div style="font-family: Arial, sans-serif; line-height:1.5; color:#333;">
  <h2 style="color:#1a73e8;">🚀 ТОП вакансій для тебе</h2>
`;

for (const item of topJobs) {
  const job = item.json;

  // Відділяємо “круті” вакансії
  let borderColor = job.ai_score >= 4 ? "#f39c12" : "#ddd"; // помаранчевий для крутих
  let background = job.ai_score >= 4 ? "#fff7e6" : "#f9f9f9"; // світлий помаранчевий для крутих

  // Зірки
  let stars = "⭐️".repeat(Math.round(job.ai_score));

  message += `
    <div style="border:2px solid ${borderColor}; padding:10px; margin-bottom:15px; border-radius:8px; background:${background};">
      <h3 style="margin:0;">${stars} ${job.title}</h3>
      <p style="margin:5px 0;"><strong>Компанія:</strong> ${job.company}</p>
      <p style="margin:5px 0;"><em>${job.ai_reason}</em></p>
      <p style="margin:5px 0;"><a href="${job.link}" style="color:#1a73e8; text-decoration:none;">Відкрити вакансію</a></p>
    </div>
  `;
}

message += `</div>`;

// 4. Повертаємо готовий HTML
return [{ json: { full_message: message } }];

const allItems = $input.all();

const cleanData = allItems.map(item => {
  const job = item.json;

  // Очищаємо текст від HTML-тегів, зайвих переносів рядків та пробілів
  const cleanDescription = (job.content || job.contentSnippet || "")
    .replace(/<[^>]*>/g, ' ') // Видаляємо всі HTML теги
    .replace(/\s+/g, ' ')     // Замінюємо кілька пробілів/ентерів на один пробіл
    .trim();

  return {
    title: job.title,
    link: job.link,
    // Тепер текст важить набагато менше, але сенс залишився
    description: cleanDescription, 
    source: job.link.includes('djinni.co') ? 'Djinni' : 'DOU'
  };
});

return [{
  json: {
    total_count: cleanData.length,
    all_jobs: cleanData
  }
}];

const items = $input.all();

if (items.length === 0) {
  return [];
}

const data = items[0].json;
const results = [];

// Проходимо по масиву заголовків (їх 4, як і вакансій)
for (let i = 0; i < data.title.length; i++) {
  results.push({
    json: {
      title: data.title[i],
      // В описі беремо кожен другий елемент (0, 2, 4, 6), бо між ними сміття
      description: data.description[i * 2] 
        ? data.description[i * 2].replace(/\n/g, ' ').trim() 
        : '',
      link: 'https://www.work.ua' + data.link[i],
      pubDate: data.pubDate[i]
    }
  });
}

return results;

// HTML відповіді HTTP Request
const html = $input.first().json.data;

if (typeof html !== 'string') {
    throw new Error("HTML не є рядком, перевір поле з відповіді HTTP Request");
}

// Витягуємо всі <li> з пагінації
const liMatches = html.match(/<ul class="pagination[^>]*">([\s\S]*?)<\/ul>/i);

let totalPages = 1;

if (liMatches) {
    const ulContent = liMatches[1];

    // Всі числа всередині <li> (ігноруємо «Попередня»/«Наступна»)
    const pageNumbers = [...ulContent.matchAll(/<a[^>]*>(\d+)<\/a>|<span[^>]*>(\d+)<\/span>/gi)]
        .map(match => parseInt(match[1] || match[2], 10))
        .filter(n => !isNaN(n));

    if (pageNumbers.length > 0) {
        totalPages = Math.max(...pageNumbers); // остання сторінка
    }
}

// Базовий URL без параметру ?page
const baseUrl = "https://www.work.ua/jobs-remote-ai+engineer/";

// Генеруємо масив усіх URL
const urls = [];
for (let i = 1; i <= totalPages; i++) {
    urls.push({ json: { url: `${baseUrl}?page=${i}` } });
}

// Повертаємо масив для наступних нод
return urls;

// Беремо всі елементи після HTTP Request + HTML Node
const allItems = $input.all();

// Ініціалізуємо словник для склеювання всіх сторінок
let combined = {
    title: [],
    description: [],
    link: [],
    pubDate: []
};

// Проходимо по всіх сторінках і додаємо дані в combined
allItems.forEach(item => {
    const page = item.json; // тут кожен item — словник {title:[], description:[], ...}
    if (page.title) combined.title = combined.title.concat(page.title);
    if (page.description) combined.description = combined.description.concat(page.description);
    if (page.link) combined.link = combined.link.concat(page.link);
    if (page.pubDate) combined.pubDate = combined.pubDate.concat(page.pubDate);
});

// Повертаємо один елемент масиву з об’єднаним словником
return [
    { json: combined }
];
